INSERT INTO `announcement` (`announcement_id`, `title`, `file_url`, `content`, `is_deleted`) VALUES
(1, 'New Community Features Are Here!', NULL, 'We’ve introduced improved community features to help you connect with fellow sports fans more easily. Join discussions, share match reactions, and stay updated with the latest activities from your favorite communities.', 0),
(2, 'Match Highlights Now Available', '/uploads/announcements/2.jpg', 'Catch up on the biggest moments from recent games with our new match highlights section. Relive incredible goals, clutch plays, and unforgettable performances all in one place.', 0),
(3, 'New Sports Communities Added', NULL, 'Explore newly added sports communities and connect with fans who share the same passion. From football and basketball to badminton and athletics, there’s a place for everyone.', 0),
(4, 'Improved Notification System', NULL, 'Never miss important updates again. Our improved notification system now delivers faster alerts for community activity, match discussions, and announcements tailored to your interests.', 0);
