INSERT INTO `community` (`community_id`, `admin_id`, `name`, `bio`, `publicity`, `created_at`, `is_deleted`) VALUES
(12, 1, 'Football Squad', 'A global football community where fans come together to celebrate goals, tactics, and unforgettable matches. Discuss your favorite clubs, players, and the moments that define the beautiful game.', 'Public', '2026-05-27 19:06:14', 0),
(13, 1, 'Track Titans', 'A space for runners, sprinters, and endurance athletes to share progress, training tips, and motivational milestones. Every step forward is a victory worth celebrating.', 'Private', '2026-05-27 19:10:03', 0),
(14, 1, 'Arena Talk', 'A place where all sports fans unite. From match analysis to player debates, this is your space to discuss everything happening in the sporting world.', 'Public', '2026-05-27 19:12:01', 1),
(15, 1, 'Pitch Vision', 'For fans who see football beyond just 90 minutes. Break down formations, analyze plays, and share the passion that drives the world’s most popular sport.', 'Private', '2026-05-27 19:18:20', 1),
(16, 4, 'Court Kings', 'A basketball community for players and fans who live for fast breaks, clutch shots, and high-intensity games. Share highlights, discuss tactics, and connect with people who understand the grind behind every win.', 'Public', '2026-05-27 19:58:01', 0),
(17, 4, 'Smash Arena', 'Where every rally counts. Discuss powerful smashes, defensive saves, and legendary matches that define the fast-paced world of badminton.', 'Private', '2026-05-27 19:58:18', 0),
(18, 4, 'Momentum Club', 'For athletes chasing personal bests and consistent improvement. This community celebrates discipline, effort, and the journey of becoming stronger every day.', 'Public', '2026-05-27 19:58:34', 0),
(19, 6, 'The Final Whistle', 'For true sports fans who stay until the end. Celebrate victories, analyze defeats, and relive iconic sports moments from around the world.', 'Public', '2026-05-27 20:20:58', 0);
