INSERT INTO `post` (`post_id`, `user_id`, `timestamp`, `description`, `publicity`, `is_deleted`, `num_of_like`, `num_of_comment`, `title`, `type`) VALUES
(15, 1, '2026-05-27 18:58:00', 'Basketball is often defined by its final moments, where pressure transforms ordinary plays into unforgettable highlights. In this post, we look at several clutch performances where players carried their teams through high-stakes situations. Whether it was a perfectly timed three-pointer, a fast break executed with precision, or a defensive stop that shifted momentum completely, these moments highlight the importance of composure under pressure. What makes clutch plays special isn’t just the skill involved, but the mental strength required to stay focused when everything is on the line. These are the moments fans remember long after the final buzzer.', 'Public', 0, 2, 1, 'Clutch Moments That Changed the Game', 'Post'),
(16, 1, '2026-05-27 19:04:56', 'This week in football delivered some of the most exciting goals across multiple leagues, reminding fans why the sport is so unpredictable and thrilling. From long-range shots that left goalkeepers stunned to intricate team plays that sliced through defenses, each goal showcased a different kind of brilliance. Some were moments of pure individual skill, while others were the result of flawless teamwork and timing. \n\nBeyond the highlights, these goals reflect the creativity, preparation, and instinct that players bring to the pitch every week, making football a continuous source of excitement for fans worldwide.', 'Public', 0, 2, 2, 'Top 5 Goals You Can’t Miss This Week', 'Post'),
(17, 4, '2026-05-27 19:52:48', 'Every athlete has one goal: to become better than yesterday. This post celebrates the journey of chasing personal bests, where improvement matters more than comparison. Behind every record broken is hours of training, discipline, and mental strength. Progress in athletics is not instant—it is earned through consistency.', 'Community', 0, 2, 1, 'Chasing Personal Bests, One Step at a Time', 'Post'),
(18, 4, '2026-05-27 19:59:32', 'In athletics, the final stretch is where true determination is revealed. Fatigue sets in, muscles burn, and every step feels heavier—but this is also where champions separate themselves. This post explores how athletes push through pain and exhaustion to finish strong when it matters most.', 'Community', 0, 2, 0, 'The Final Stretch: Where Races Are Won', 'Post'),
(19, 4, '2026-05-27 20:32:53', 'all wierdos', 'Public', 0, 0, 0, 'hahahah', 'Post'),
(20, 4, '2026-05-27 20:34:17', 'what are u doing', 'Public', 1, 0, 0, 'are u guys gangsters', 'Post'),
(21, 4, '2026-05-27 20:35:36', 'He didn\'t even sleep yesterday, what is he doing', 'Public', 0, 0, 0, 'Jimmy is super crazy', 'Post'),
(22, 7, '2026-05-27 20:41:34', 'Performance-focused basketball gear designed for players who value speed, control, and confidence on the court. From lightweight jerseys to durable training equipment, Apex Hoops supports athletes at every level of the game.', 'Public', 0, 0, 0, 'Apex Hoops', 'Advertisement'),
(23, 7, '2026-05-27 20:43:08', 'Built for badminton enthusiasts who value consistency and control. ShuttlePro offers reliable rackets, accessories, and training essentials for players of all skill levels.', 'Public', 0, 0, 0, 'ShuttlePro', 'Advertisement'),
(24, 7, '2026-05-27 20:44:30', 'Success on the field is built through discipline and preparation. StrikerX provides the equipment and comfort athletes need to train confidently and perform at their best.', 'Public', 0, 0, 0, 'StrikerX', 'Advertisement'),
(25, 1, '2026-05-27 20:49:41', 'we are hosting a badminton match this Sunday', 'Community', 0, 0, 0, 'Come and Join Us', 'Post'),
(26, 1, '2026-05-27 20:50:30', 'Athletics teaches athletes that improvement does not happen overnight. Every training session, every early morning run, and every extra effort contributes to long-term growth. Even small improvements matter because consistency eventually leads to bigger achievements. Success in athletics is built through patience, discipline, and the willingness to keep going even when progress feels slow.', 'Community', 0, 0, 0, 'Small Progress Is Still Progress', 'Post');
